def publish(event_or_name, payload = nil)
  if event_or_name.is_a?(String)
    # Legacy string-based publish
    event = Events::BaseEvent.new(name: event_or_name, payload: payload || {})
    @subscribers[event_or_name].each { |h| h.call(event.payload) }
  else
    raise ArgumentError unless event_or_name.is_a?(Events::BaseEvent)
    event = event_or_name
    @subscribers[event.class].each { |h| h.call(event) }
  end

  logger.info("Published #{event.name}")
